-- ============================================================
-- AgriSage — Base de données ONSSA Index Phytosanitaire
-- Généré le 2026-06-23 | Source : ONSSA eservice
-- 1355 produits | 4657 usages | 179 cultures | 653 MA
-- ============================================================


-- EXTENSION pour UUID (PostgreSQL)
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ── TABLE PRODUITS ────────────────────────────────────────────────────────
DROP TABLE IF EXISTS usages CASCADE;
DROP TABLE IF EXISTS produits CASCADE;
DROP TABLE IF EXISTS cultures CASCADE;
DROP TABLE IF EXISTS matieres_actives CASCADE;

CREATE TABLE produits (
    id                    SERIAL PRIMARY KEY,
    nom_commercial        VARCHAR(200) NOT NULL,
    detenteur             VARCHAR(200),
    fournisseur           VARCHAR(200),
    numero_homologation   VARCHAR(50) UNIQUE,
    valable_jusquau       DATE,
    tableau_toxicologique VARCHAR(10),
    categorie             VARCHAR(100),
    type_produit          VARCHAR(50),
    formulation           VARCHAR(200),
    matiere_active        TEXT,
    teneur                VARCHAR(100),
    statut                VARCHAR(20) DEFAULT 'homologue',
    date_import           DATE,
    created_at            TIMESTAMP DEFAULT NOW(),
    updated_at            TIMESTAMP DEFAULT NOW()
);

COMMENT ON TABLE produits IS 'Index phytosanitaire ONSSA Maroc — produits homologués';
COMMENT ON COLUMN produits.type_produit IS 'fongicide|insecticide|herbicide|acaricide|nematicide|molluscicide|...';
COMMENT ON COLUMN produits.statut IS 'homologue|retire|suspendu';

-- ── TABLE USAGES ─────────────────────────────────────────────────────────
CREATE TABLE usages (
    id              SERIAL PRIMARY KEY,
    produit_id      INTEGER NOT NULL REFERENCES produits(id) ON DELETE CASCADE,
    culture         VARCHAR(200),
    usage_desc      TEXT,
    dose            VARCHAR(100),
    dar_raw         VARCHAR(20),
    dar_jours       INTEGER,
    nb_applications VARCHAR(20),
    created_at      TIMESTAMP DEFAULT NOW()
);

COMMENT ON TABLE usages IS 'Un usage = une culture homologuée pour un produit donné';
COMMENT ON COLUMN usages.dar_jours IS 'Délai Avant Récolte en jours (parsé depuis dar_raw)';

-- ── TABLE CULTURES ────────────────────────────────────────────────────────
CREATE TABLE cultures (
    id              SERIAL PRIMARY KEY,
    nom_fr          VARCHAR(200) UNIQUE NOT NULL,
    nom_ar          VARCHAR(200),
    famille         VARCHAR(100),
    nb_produits     INTEGER DEFAULT 0,
    created_at      TIMESTAMP DEFAULT NOW()
);

-- ── TABLE MATIÈRES ACTIVES ────────────────────────────────────────────────
CREATE TABLE matieres_actives (
    id           SERIAL PRIMARY KEY,
    nom_complet  VARCHAR(300) UNIQUE NOT NULL,
    nom_base     VARCHAR(200),
    groupe_frac  VARCHAR(20),
    groupe_irac  VARCHAR(20),
    groupe_hrac  VARCHAR(20),
    risque_resistance VARCHAR(20),
    nb_produits  INTEGER DEFAULT 0,
    created_at   TIMESTAMP DEFAULT NOW()
);

COMMENT ON COLUMN matieres_actives.groupe_frac IS 'À enrichir depuis les classifications FRAC officielles';
COMMENT ON COLUMN matieres_actives.groupe_irac IS 'À enrichir depuis les classifications IRAC officielles';
COMMENT ON COLUMN matieres_actives.groupe_hrac IS 'À enrichir depuis les classifications HRAC officielles';

-- ── INDEX PERFORMANCE ─────────────────────────────────────────────────────
CREATE INDEX idx_produits_type       ON produits(type_produit);
CREATE INDEX idx_produits_categorie  ON produits(categorie);
CREATE INDEX idx_produits_ma         ON produits(matiere_active);
CREATE INDEX idx_produits_statut     ON produits(statut);
CREATE INDEX idx_usages_culture      ON usages(culture);
CREATE INDEX idx_usages_produit      ON usages(produit_id);
CREATE INDEX idx_usages_dar          ON usages(dar_jours);
CREATE INDEX idx_usages_culture_type ON usages(culture, produit_id);

