-- ── VUES UTILES POUR L'API ────────────────────────────────────────────────

CREATE OR REPLACE VIEW v_produits_complets AS
SELECT
    p.id,
    p.nom_commercial,
    p.numero_homologation,
    p.detenteur,
    p.categorie,
    p.type_produit,
    p.formulation,
    p.matiere_active,
    p.teneur,
    p.valable_jusquau,
    p.tableau_toxicologique,
    p.statut,
    COUNT(u.id) as nb_usages,
    ARRAY_AGG(DISTINCT u.culture) FILTER (WHERE u.culture IS NOT NULL AND u.culture != '') as cultures,
    MIN(u.dar_jours) as dar_min,
    MAX(u.dar_jours) as dar_max
FROM produits p
LEFT JOIN usages u ON p.id = u.produit_id
GROUP BY p.id;

CREATE OR REPLACE VIEW v_conseil_base AS
SELECT
    p.id as produit_id,
    p.nom_commercial,
    p.numero_homologation,
    p.type_produit,
    p.categorie,
    p.formulation,
    p.matiere_active,
    p.teneur,
    p.valable_jusquau,
    p.tableau_toxicologique,
    p.statut,
    u.culture,
    u.usage_desc,
    u.dose,
    u.dar_jours,
    u.dar_raw,
    u.nb_applications,
    ma.groupe_frac,
    ma.groupe_irac,
    ma.groupe_hrac,
    ma.risque_resistance
FROM produits p
JOIN usages u ON p.id = u.produit_id
LEFT JOIN matieres_actives ma ON p.matiere_active = ma.nom_complet
WHERE p.statut = 'homologue';

COMMENT ON VIEW v_conseil_base IS 'Vue principale pour le moteur de conseil AgriSage API';

