-- ── TRIGGER mise à jour updated_at ────────────────────────────────────────
CREATE OR REPLACE FUNCTION update_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_produits_updated_at
BEFORE UPDATE ON produits
FOR EACH ROW EXECUTE FUNCTION update_updated_at();
